class GpuCostAnalyzer:
    RATES = {
        "nvidia-a100-80gb": 3.50,
        "nvidia-h100-80gb": 8.50,
        "nvidia-a10g": 1.20,
    }
    DOWNGRADE_MAP = {
        "nvidia-h100-80gb": "nvidia-a100-80gb",
        "nvidia-a100-80gb": "nvidia-a10g",
    }

    def __init__(self, records: list[dict]):
        self.records = records

    def compute_chargeback(self) -> dict:
        team_costs = {}
        for r in self.records:
            team = r["team"]
            cost = round(r["gpu_hours"] * self.RATES.get(r["gpu_model"], 5.00), 2)
            if team not in team_costs:
                team_costs[team] = 0.0
            team_costs[team] = round(team_costs[team] + cost, 2)
        return team_costs

    def find_wasteful_allocations(self, threshold=30.0) -> list:
        wasteful = [r for r in self.records if r["utilization_pct"] < threshold]
        return sorted(wasteful, key=lambda r: r["utilization_pct"])

    def recommend_rightsizing(self) -> list[dict]:
        recommendations = []
        for r in self.records:
            if r["utilization_pct"] < 30.0 and r["gpu_model"] in self.DOWNGRADE_MAP:
                recommendations.append({
                    "team": r["team"],
                    "current_gpu": r["gpu_model"],
                    "recommended_gpu": self.DOWNGRADE_MAP[r["gpu_model"]],
                    "utilization_pct": r["utilization_pct"],
                    "potential_savings": round(
                        r["gpu_hours"] * (
                            self.RATES[r["gpu_model"]]
                            - self.RATES[self.DOWNGRADE_MAP[r["gpu_model"]]]
                        ), 2
                    ),
                })
        return recommendations
